import { provide, reactive, toRefs } from "vue";
import bus from '@/utils/bus'
interface delList {
    selectedRowKeys: [];
    hasSelected: boolean;
}
import { delPerson } from '@/server/http/api/role'
// 批量删除
export function dellist() {
    let state = reactive({
        selectedRowKeys: [],
        hasSelected: false,
        loading: false
    });

    function onhasSelected(options: delList) {
        //console.log(options);

        state.selectedRowKeys = options.selectedRowKeys
        state.hasSelected = options.hasSelected
    }
    const start = () => {
        state.loading = true;
        delPerson(state.selectedRowKeys).then((res: any) => {
            state.loading = false;
            bus.emit('delPresonlist')
        })

    };
    return {
        onhasSelected,
        ...toRefs(state),
        start,
    }
}