
import { ref, defineComponent, reactive, inject, toRaw } from "vue";
import TreeNode from "@/components/tree/TreeNode.vue";
import { addPerson } from "@/server/http/api/role";
export default defineComponent({
  props: ["DepartmentList"],
  components: {
    TreeNode,
  },
  setup() {
    const formRef = ref();

    const rules = {
      name: [
        { required: true, message: "账号不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "内容在64个字符之内", trigger: "blur" },
      ],
      jobnumber: [
        { required: true, message: "编号不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "内容在64个字符之内", trigger: "blur" },
      ],
      position: [
        { required: true, message: "职位不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "内容在64个字符之内", trigger: "blur" },
      ],
      department: [
        {
          type: "array",
          required: true,
          message: "部门不能为空",
          trigger: "blur",
        },
      ],
      mobile: [
        { required: true, message: "手机号不能为空", trigger: "blur" },

        {
          pattern:
            /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
          message: "手机号不合法",
          trigger: "blur",
        },
      ],
    };
    let initPersonList: any = inject("initPersonList");

    const formState: any = reactive({
      name: "",
      position: "",
      jobnumber: "",
      department: [],
      mobile: "",
      orgemail: "",
      email: "",
    });

    function onDepartmentID(options: any) {
      formState.dev = options.name;
      formState.deptId = options.id;
    }
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);

    const showModal = () => {
      visible.value = true;
    };

    const handleOk = () => {
      formRef.value
        .validate()
        .then(() => {
          confirmLoading.value = true;
          let FromObj: any = {};
          Object.assign(FromObj, toRaw(formState));

          Object.assign(FromObj, {
            department: formState.department.join(","),
          });
          addPerson(FromObj).then((res: any) => {
            visible.value = false;
            confirmLoading.value = false;

            formState.name = "";
            formState.position = "";
            formState.email = "";
            formState.mobile = "";
            formState.jobnumber = "";
            formState.orgemail = "";
            formState.department = [];

            if (res.data.code === 200) {
              initPersonList();
            }
          });
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    };
    return {
      formState,
      visible,
      confirmLoading,
      showModal,
      handleOk,
      labelCol: { span: 4 },
      wrapperCol: { span: 20 },
      onDepartmentID,
      rules,
      formRef,
    };
  },
});
