
import {
  defineComponent,
  reactive,
  ref,
  provide,
  toRefs,
  watch,
  onMounted,
  onUnmounted,
} from "vue";
import { DownloadOutlined } from "@ant-design/icons-vue";
import TableRole from "@/components/tablerole/TableRole.vue";
import AddPreson from "./person/AddPreson.vue";
import { dellist } from "./person/dellist";
import { PersonList, deptsonList } from "@/server/http/api/role";
import TreeNode from "@/components/tree/TreeNode.vue";
// import { PersonExport } from "@/server/DownLoad";
import bus from "@/utils/bus";
import { useStore } from "vuex";

export default defineComponent({
  name: "Person",
  components: {
    TableRole,
    AddPreson,
    DownloadOutlined,
    TreeNode,
  },

  setup() {
    // 批量删除
    const del = dellist();
    // 页面搜索

    const personList = ref([]);
    let flag = ref(true);
    let Pagination: any = reactive({
      pageNum: 1,
      pageSize: 10,
      isInclude: "1",
      id: "",
    });
    watch(flag, (newVal) => {
      if (newVal) {
        Pagination.isInclude = 1;
      } else {
        Pagination.isInclude = 0;
      }
    });
    let total = ref(0);
    let search = ref("");
    function init() {
      PersonList({
        pageNum: Pagination.pageNum,
        pageSize: Pagination.pageSize,
        isInclude: Pagination.isInclude,
        search: search.value,
        id: Pagination.id,
      }).then((res: any) => {
        if (res.data.code === 200) {
          personList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }

    watch(
      Pagination,
      (newval, o) => {
        PersonList({
          pageNum: Pagination.pageNum,
          pageSize: Pagination.pageSize,
          isInclude: Pagination.isInclude,
          search: search.value,
          id: Pagination.id,
        }).then((res: any) => {
          if (res.data.code === 200) {
            personList.value = res.data.data.list;
            total.value = res.data.data.total;
          }
        });
      },
      {
        immediate: true,
      }
    );
    const onSearch = (searchValue: string) => {
      init();
    };
    let timer: any;
    const onChange = () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        init();
      }, 600);
    };

    // 部门
    // 架构
    // ====
    const visible = ref(true);
    const titleTip = ref("");
    const afterVisibleChange = (bool: boolean) => {
      //console.log("visible", bool);
    };

    const showDrawer = () => {
      visible.value = true;
    };

    const onClose = () => {
      visible.value = false;
    };

    onMounted(() => {
      visible.value = false;
      bus.on("delPresonlist", () => {
        init();
      });
    });
    onUnmounted(() => {
      bus.off("delPresonlist");
    });
    // ====

    function onDepartmentID(options: any) {
      visible.value = false;
      titleTip.value = options.name;
      Pagination.id = options.id;
    }

    provide("initPersonList", init);
    const store = useStore();

    // function download() {
    //   let userInfo: any = JSON.parse(store.state.userInfo.userInfo);

    //   PersonExport(search.value, userInfo.userId);
    // }
    let DepartmentList: any = ref([]);
    deptsonList().then((res: any) => {
      if (res.data.code === 200) {
        res.data.data.map((item: any) => {
          DepartmentList.value.push({ label: item.name, value: item.id + "" });
        });
      }
      // //console.log(DepartmentList.value);
    });
    return {
      ...del,
      total,
      onSearch,
      onChange,
      personList,
      onDepartmentID,
      init,
      search,
      Pagination,
      // ===
      visible,
      afterVisibleChange,
      showDrawer,
      onClose,
      titleTip,
      flag,
      DepartmentList,
      //   download,
    };
  },
});
